SELECT ?author WHERE {
  ?author wdt:P1658 wd:Q7243277.
  ?author p:P1658 [
    ps:P1658 wd:Q7243277;
    pq:P585 ?year
  ].
  FILTER(year(?year) = 2012).
  ?author wdt:P39 ?position.
  ?position wdt:P1344 wd:Q1967496.
  ?position rdfs:label "Deputy Chair"@en.
}

SELECT ?author WHERE {
  ?work wdt:P1658 wd:Q7243277 .
  ?work p:P1658 [
    ps:P1658 wd:Q7243277;
    pq:P585 ?awardYear
  ].
